import android.content.Context
import android.content.Intent
import androidx.activity.result.ActivityResultLauncher
import androidx.activity.result.IntentSenderRequest
import com.facebook.CallbackManager
import com.facebook.FacebookCallback
import com.facebook.FacebookException
import com.facebook.login.LoginManager
import com.facebook.login.LoginResult
import com.google.android.gms.auth.api.identity.BeginSignInRequest
import com.google.android.gms.auth.api.identity.Identity
import com.google.android.gms.auth.api.identity.SignInClient

sealed class SocialLoginResult {
    data class Success(val provider: String, val authCode: String, val email: String?) : SocialLoginResult()
    data class Error(val message: String) : SocialLoginResult()
    object Cancelled : SocialLoginResult()
}

class SocialLoginManager(private val context: Context) {

    private var oneTapClient: SignInClient? = null
    private val callbackManager = CallbackManager.Factory.create()
    private var loginCallback: ((SocialLoginResult) -> Unit)? = null

    // ---- Google Sign-In (One Tap) ----

    fun initGoogleSignIn() {
        oneTapClient = Identity.getSignInClient(context)
    }

    fun buildGoogleSignInRequest(): BeginSignInRequest {
        return BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    // Server client ID (public) is fine to include
                    .setServerClientId(SocialLoginConfig.googleClientId)
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()
    }

    fun startGoogleSignIn(
        launcher: ActivityResultLauncher<IntentSenderRequest>,
        callback: (SocialLoginResult) -> Unit
    ) {
        loginCallback = callback
        val signInRequest = buildGoogleSignInRequest()

        oneTapClient?.beginSignIn(signInRequest)
            ?.addOnSuccessListener { result ->
                val intentSenderRequest = IntentSenderRequest.Builder(result.pendingIntent.intentSender).build()
                launcher.launch(intentSenderRequest)
            }
            ?.addOnFailureListener { e ->
                callback(SocialLoginResult.Error("Google Sign-In failed: ${e.localizedMessage}"))
            }
    }

    fun handleGoogleSignInResult(data: Intent?): SocialLoginResult {
        return try {
            val credential = oneTapClient?.getSignInCredentialFromIntent(data)
            val idToken = credential?.googleIdToken
            if (idToken != null) {
                // Send this ID token to YOUR BACKEND SERVER
                // Your server validates it and exchanges using the secret stored server-side
                SocialLoginResult.Success(
                    provider = "google",
                    authCode = idToken,
                    email = credential.id
                )
            } else {
                SocialLoginResult.Error("No ID token received from Google")
            }
        } catch (e: Exception) {
            SocialLoginResult.Error("Google sign-in error: ${e.localizedMessage}")
        }
    }

    // ---- Facebook Login ----

    fun initFacebookLogin(callback: (SocialLoginResult) -> Unit) {
        loginCallback = callback

        LoginManager.getInstance().registerCallback(
            callbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    // Send the access token to YOUR BACKEND SERVER
                    // Your server validates and processes using the secret stored server-side
                    callback(
                        SocialLoginResult.Success(
                            provider = "facebook",
                            authCode = result.accessToken.token,
                            email = null // Fetch via Graph API on your backend
                        )
                    )
                }

                override fun onCancel() {
                    callback(SocialLoginResult.Cancelled)
                }

                override fun onError(error: FacebookException) {
                    callback(SocialLoginResult.Error("Facebook login error: ${error.localizedMessage}"))
                }
            }
        )
    }

    fun startFacebookLogin(activity: androidx.activity.ComponentActivity) {
        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            callbackManager,
            listOf("email", "public_profile")
        )
    }

    fun handleFacebookActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    // ---- Sign Out ----

    fun signOut() {
        oneTapClient?.signOut()
        LoginManager.getInstance().logOut()
    }
}

