import android.os.Bundle
import android.util.Log
import android.widget.Toast
import androidx.activity.ComponentActivity
import androidx.activity.result.contract.ActivityResultContracts

class LoginActivity : ComponentActivity() {

    private lateinit var socialLoginManager: SocialLoginManager

    private val googleSignInLauncher = registerForActivityResult(
        ActivityResultContracts.StartIntentSenderForResult()
    ) { result ->
        val loginResult = socialLoginManager.handleGoogleSignInResult(result.data)
        handleLoginResult(loginResult)
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        socialLoginManager = SocialLoginManager(this)
        socialLoginManager.initGoogleSignIn()

        // Wire up your Google sign-in button
        // googleSignInButton.setOnClickListener { startGoogleLogin() }

        // Wire up your Facebook sign-in button
        // facebookSignInButton.setOnClickListener { startFacebookLogin() }
    }

    private fun startGoogleLogin() {
        socialLoginManager.startGoogleSignIn(googleSignInLauncher) { result ->
            handleLoginResult(result)
        }
    }

    private fun startFacebookLogin() {
        socialLoginManager.initFacebookLogin { result ->
            handleLoginResult(result)
        }
        socialLoginManager.startFacebookLogin(this)
    }

    private fun handleLoginResult(result: SocialLoginResult) {
        when (result) {
            is SocialLoginResult.Success -> {
                Log.d("Login", "Provider: ${result.provider}, Email: ${result.email}")
                // Send result.authCode to YOUR BACKEND SERVER
                // The server uses the secrets to validate and create a session
                sendTokenToBackend(result.provider, result.authCode)
            }
            is SocialLoginResult.Error -> {
                Toast.makeText(this, result.message, Toast.LENGTH_LONG).show()
            }
            is SocialLoginResult.Cancelled -> {
                Toast.makeText(this, "Login cancelled", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun sendTokenToBackend(provider: String, token: String) {
        // Use Retrofit/Ktor client to send the token to your server
        // Your server (which has the secrets) validates and returns a session
        // Example:
        // apiService.authenticate(AuthRequest(provider, token))
    }
}